implementation.c:script:
import io.nop.orm.IOrmEntity;
import io.nop.core.lang.sql.SQL;

// 获取 DAO
let userDao = inject('dao_t_user');

// 查询所有需要处理的用户
let query = new QueryBean();
query.eq('delFlag', 0);
query.eq('status', 1);

let users = userDao.findListByQuery(query);
let processed = 0;

// 处理每个用户
for (user in users) {
    let changed = false;

    // 自动生成用户名（如果为空）
    if (user.userName == null || user.userName == '') {
        user.userName = 'user_' + user.userId;
        changed = true;
    }

    // 根据邮箱自动设置真实姓名（示例逻辑）
    if (user.realName == null && user.email != null) {
        let emailName = user.email.split('@')[0];
        user.realName = emailName;
        changed = true;
    }

    // 保存修改
    if (changed) {
        userDao.updateEntity(user);
        processed++;
    }
}

// 记录日志
log.info('处理了 {} 个用户数据', processed);

sql.body:
-- 创建全文索引（MySQL 和 PostgreSQL 都支持）
CREATE FULLTEXT INDEX idx_user_name_ft 
ON t_user(user_name);

-- Oracle 使用位图索引
CREATE BITMAP INDEX idx_user_status_bmap 
ON t_user(status);

-- SQL Server 使用聚集列存储索引
CREATE CLUSTERED COLUMNSTORE INDEX idx_user_cstore 
ON t_user;
